import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  CreditCard, Plus, Trash2, X, Save, ShoppingCart, Calendar 
} from 'lucide-react';

const Cartoes = () => {
  const [cartoes, setCartoes] = useState([]);
  const [compras, setCompras] = useState([]); // Todas as compras para cálculo
  const [showModal, setShowModal] = useState(false);
  const [selectedCartao, setSelectedCartao] = useState(null); // Para ver detalhes
  const [loading, setLoading] = useState(true);
  
  const [novoCartao, setNovoCartao] = useState({
    nome: '', limite: '', dia_fechamento: '', dia_vencimento: '', cor: '#4f46e5'
  });

  const mesAtual = new Date().getMonth();
  const anoAtual = new Date().getFullYear();

  useEffect(() => {
    fetchDados();
  }, []);

  async function fetchDados() {
    setLoading(true);
    // Busca Cartões
    const { data: cData } = await supabase.from('cartoes').select('*').order('nome');
    // Busca Compras para calcular disponível e mostrar no modal
    const { data: compData } = await supabase.from('compras').select('*');
    
    setCartoes(cData || []);
    setCompras(compData || []);
    setLoading(false);
  }

  // Lógica para calcular o quanto já foi gasto no cartão ESPECIFICAMENTE no mês atual
  const calcularDisponivel = (cartaoNome, limite) => {
    const gastosMes = compras.reduce((acc, item) => {
      if (item.cartao !== cartaoNome) return acc;

      const numParcelas = item.num_parcelas || 1;
      let valorNoMes = 0;

      for (let i = 0; i < numParcelas; i++) {
        const dataCompra = new Date(item.data_compra);
        const dataParcela = new Date(dataCompra.getFullYear(), dataCompra.getMonth() + i, 1);
        
        if (dataParcela.getMonth() === mesAtual && dataParcela.getFullYear() === anoAtual) {
          valorNoMes = parseFloat(item.valor_total) / numParcelas;
        }
      }
      return acc + valorNoMes;
    }, 0);

    return limite - gastosMes;
  };

  async function handleSave(e) {
    e.preventDefault();
    const { error } = await supabase.from('cartoes').insert([{ 
      ...novoCartao, 
      limite: parseFloat(novoCartao.limite),
      dia_fechamento: parseInt(novoCartao.dia_fechamento),
      dia_vencimento: parseInt(novoCartao.dia_vencimento)
    }]);

    if (!error) {
      setShowModal(false);
      setNovoCartao({ nome: '', limite: '', dia_fechamento: '', dia_vencimento: '', cor: '#4f46e5' });
      fetchDados();
    }
  }

  const formatMoney = (v) => `R$ ${parseFloat(v).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`;

  return (
    <div className="fade-in">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '32px' }}>
        <div>
          <h1 style={{ margin: 0, fontSize: '1.8rem' }}>Meus Cartões</h1>
          <p style={{ color: 'var(--text-muted)' }}>Clique no cartão para ver as compras do mês.</p>
        </div>
        <button className="btn-primary" onClick={() => setShowModal(true)}>
          <Plus size={20} /> Adicionar
        </button>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(320px, 1fr))', gap: '24px' }}>
        {cartoes.map(cartao => {
          const disponivel = calcularDisponivel(cartao.nome, cartao.limite);
          const perc = (disponivel / cartao.limite) * 100;

          return (
            <div key={cartao.id} className="card card-hover" 
              onClick={() => setSelectedCartao(cartao)}
              style={{ 
                background: `linear-gradient(135deg, ${cartao.cor}, #1e293b)`, 
                color: 'white', padding: '24px', cursor: 'pointer' 
              }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
                <span style={{ fontWeight: 700, fontSize: '1.2rem' }}>{cartao.nome}</span>
                <CreditCard opacity={0.5} />
              </div>
              
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' }}>
                <div>
                  <small style={{ opacity: 0.7, fontSize: '0.6rem' }}>LIMITE TOTAL</small>
                  <div style={{ fontSize: '1.1rem', fontWeight: 600 }}>{formatMoney(cartao.limite)}</div>
                </div>
                <div>
                  <small style={{ opacity: 0.7, fontSize: '0.6rem' }}>DISPONÍVEL</small>
                  <div style={{ fontSize: '1.1rem', fontWeight: 600, color: disponivel < 500 ? '#fca5a5' : '#6ee7b7' }}>
                    {formatMoney(disponivel)}
                  </div>
                </div>
              </div>

              {/* Barra de Progresso do Limite */}
              <div style={{ background: 'rgba(255,255,255,0.1)', height: '6px', borderRadius: '10px', marginTop: '15px', overflow: 'hidden' }}>
                <div style={{ background: 'white', height: '100%', width: `${perc}%`, transition: '0.5s' }} />
              </div>
            </div>
          );
        })}
      </div>

      {/* MODAL 1: ADICIONAR NOVO CARTÃO */}
      {showModal && (
        <div className="modal-overlay">
          <div className="modal-content">
            <div className="modal-header">
              <h3>Novo Cartão</h3>
              <X className="btn-close" onClick={() => setShowModal(false)} />
            </div>
            <form onSubmit={handleSave}>
               <input className="form-control" placeholder="Nome do Banco" required onChange={e => setNovoCartao({...novoCartao, nome: e.target.value})} />
               <input className="form-control" type="number" placeholder="Limite" required onChange={e => setNovoCartao({...novoCartao, limite: e.target.value})} style={{marginTop: '10px'}}/>
               <div className="form-grid" style={{marginTop: '10px'}}>
                  <input className="form-control" type="number" placeholder="Dia Fechamento" onChange={e => setNovoCartao({...novoCartao, dia_fechamento: e.target.value})} />
                  <input className="form-control" type="number" placeholder="Dia Vencimento" onChange={e => setNovoCartao({...novoCartao, dia_vencimento: e.target.value})} />
               </div>
               <input type="color" className="form-control" value={novoCartao.cor} onChange={e => setNovoCartao({...novoCartao, cor: e.target.value})} style={{marginTop: '10px', height: '40px'}} />
               <button type="submit" className="btn-primary" style={{width: '100%', marginTop: '20px'}}>Salvar</button>
            </form>
          </div>
        </div>
      )}

      {/* MODAL 2: DETALHES/COMPRAS DO CARTÃO SELECIONADO */}
      {selectedCartao && (
        <div className="modal-overlay">
          <div className="modal-content" style={{ maxWidth: '600px', width: '90%' }}>
            <div className="modal-header">
              <div>
                <h3 style={{ margin: 0 }}>{selectedCartao.nome}</h3>
                <small style={{ color: 'var(--text-muted)' }}>Compras de {new Date().toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' })}</small>
              </div>
              <X className="btn-close" onClick={() => setSelectedCartao(null)} />
            </div>

            <div style={{ maxHeight: '400px', overflowY: 'auto', marginTop: '15px' }}>
              {compras.filter(c => c.cartao === selectedCartao.nome).map((item, idx) => {
                // Verificar se esta compra cai no mês atual
                const numParcelas = item.num_parcelas || 1;
                let parcelaInfo = null;

                for (let i = 0; i < numParcelas; i++) {
                  const dC = new Date(item.data_compra);
                  const dP = new Date(dC.getFullYear(), dC.getMonth() + i, 1);
                  if (dP.getMonth() === mesAtual && dP.getFullYear() === anoAtual) {
                    parcelaInfo = { atual: i + 1, total: numParcelas, valor: parseFloat(item.valor_total) / numParcelas };
                  }
                }

                if (!parcelaInfo) return null;

                return (
                  <div key={idx} style={{ display: 'flex', justifyContent: 'space-between', padding: '12px', borderBottom: '1px solid var(--border)', alignItems: 'center' }}>
                    <div>
                      <div style={{ fontWeight: '600', fontSize: '0.9rem' }}>{item.descricao}</div>
                      <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', display: 'flex', gap: '10px' }}>
                        <span><Calendar size={12} /> {new Date(item.data_compra).toLocaleDateString()}</span>
                        {item.parcelado && <span style={{ color: 'var(--primary)', fontWeight: 'bold' }}>{parcelaInfo.atual}/{parcelaInfo.total}</span>}
                      </div>
                    </div>
                    <div style={{ fontWeight: '700' }}>{formatMoney(parcelaInfo.valor)}</div>
                  </div>
                );
              })}
              {compras.filter(c => c.cartao === selectedCartao.nome).length === 0 && (
                <p style={{ textAlign: 'center', padding: '20px', color: 'var(--text-muted)' }}>Nenhuma compra este mês.</p>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Cartoes;
